                  import sailpoint.tools.Util;
                  import java.util.Calendar;
                  import java.util.Date;
                  import java.util.List;


                  /* ==============================
                     READ INPUTS
                     ============================== */

                  String daysSinceAssignment = (String) args.get("daysSinceAssignment");
                  List roleMinistryList = (List) args.get("roleMinistry");
                  List roleNameContainsList = (List) args.get("roleNameContains");
                  List jobCodeList = (List) args.get("jobCode");
                  List businessUnitList = (List) args.get("businessUnit");
                  Date roleCreatedDateInput = (Date) args.get("roleCreatedDate");
                  
                  
                  /* ==============================
                     BASE FILTER
                     ============================== */

                  query = query + " AND identity.inactive = false";

                  /* ==============================
                     DAYS SINCE ASSIGNMENT 
                     ============================== */

                  Calendar calAssign = Calendar.getInstance();
                  if (Util.isNotNullOrEmpty(daysSinceAssignment)) {
                  	int days = Integer.parseInt(daysSinceAssignment);
                    	calAssign.add(Calendar.DAY_OF_YEAR, -days);
                  		
                  	Date pastDate = calAssign.getTime();
                    	args.put("pastDate", pastDate);
                    	query = query + " AND ie.created >= :pastDate";
                  	}

                  /* ==============================
                     ROLE CREATED DATE
                     ============================== */

                  Calendar calRole = Calendar.getInstance();
                  if(roleCreatedDateInput != null) {
                     calRole.setTime(roleCreatedDateInput);
                     Date roleCreatedDate = calRole.getTime();
                     args.put("roleCreatedDate", roleCreatedDate);
                     query = query + " AND bundle.created >= :roleCreatedDate";
                  	}
                  /* ==============================
                     ROLE MINISTRY
                     ============================== */

                  if (roleMinistryList != null && !roleMinistryList.isEmpty()) {
                    query = query + " AND bundle.ministry IN :roleMinistry";
                    args.put("roleMinistry", roleMinistryList);
                  }
                  
                  /* ==============================
                     ROLE NAME CONTAINS
                     ============================== */
									
                	if (roleNameContainsList != null && !roleNameContainsList.isEmpty()) {

                  StringBuilder clause = new StringBuilder(" AND (");

                  for (int i = 0; i < roleNameContainsList.size(); i++) {
                      if (i > 0) clause.append(" OR ");

                      String val = roleNameContainsList.get(i).replace("'", "''");
                      clause.append(" ie.value LIKE '%").append(val).append("%'");
                  	}
									 	clause.append(")");
                      query += clause.toString();
                 	}

                  /* ==============================
                     JOB CODE 
                     ============================== */

                  if (jobCodeList != null && !jobCodeList.isEmpty()) {
                    query = query + " AND identity.attributes.jobcode IN :jobCode";
                    args.put("jobCode", jobCodeList);
                  }

                  /* ==============================
                     BUSINESS UNIT
                     ============================== */

                  if (businessUnitList != null && !businessUnitList.isEmpty()) {
                    query = query + " AND identity.attributes.businessUnit IN :businessUnit";
                    args.put("businessUnit", businessUnitList);
                  }
 
                  return query;
